import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const LABELS = {
  '1': { text: '진행중', color: '#4caf50' },
  '0': { text: '모집완료', color: '#f44336' },
};

function getMemberTagColor(memberCount, totalCount) {
  if (!totalCount || totalCount === 0) return '#4caf50';
  const ratio = memberCount / totalCount;
  if (ratio <= 0.3) return '#f44336'; // 30% 이하 빨강
  if (ratio <= 0.5) return '#ff9800'; // 50% 이하 주황
  return '#4caf50'; // 기본 녹색
}

function PostsList() {
  const [posts, setPosts] = useState([]);
  const [showRecruiting, setShowRecruiting] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    fetch(`/api/posts${showRecruiting ? '?recruiting=true' : ''}`)
      .then(res => res.json())
      .then(data => setPosts(data.posts || []));
  }, [showRecruiting]);

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #43a047 80%, #fff 100%)',
      paddingTop: 60,
      paddingBottom: 60,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
    }}>
      <div style={{ maxWidth: 900, width: '100%', margin: '0 auto', marginTop: 32 }}>
        <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: 18 }}>
          <label style={{ color: '#fff', fontWeight: 600, fontSize: 15, background: 'rgba(0,0,0,0.08)', borderRadius: 8, padding: '4px 12px' }}>
            <input type="checkbox" checked={showRecruiting} onChange={e => setShowRecruiting(e.target.checked)} style={{ marginRight: 6 }} />
            진행중만 표시
          </label>
        </div>
        <div style={{
          display: 'flex',
          alignItems: 'center',
          background: 'rgba(255,255,255,0.85)',
          borderRadius: 14,
          boxShadow: '0 1px 4px #b0c4de',
          marginBottom: 18,
          padding: '12px 24px',
          fontWeight: 700,
          fontSize: 16,
          color: '#388e3c',
          gap: 18,
        }}>
          <span style={{ minWidth: 70, textAlign: 'center' }}>상태</span>
          <span style={{ minWidth: 90, textAlign: 'center' }}>모집인원</span>
          <span style={{ flex: 2 }}>제목</span>
          <span style={{ flex: 2 }}>태그</span>
          <span style={{ flex: 1 }}>작성자</span>
          <span style={{ flex: 1 }}>작성일</span>
          <span style={{ flex: 0.7, textAlign: 'right' }}>조회수</span>
        </div>
        {posts.map(post => {
          const totalCount = post.total_member_count || post.member_count + (post.applicant_count || 0);
          const memberTagColor = getMemberTagColor(post.member_count, totalCount);
          return (
            <div
              key={post.id}
              onClick={() => navigate(`/posts/${post.id}`)}
              style={{
                display: 'flex',
                alignItems: 'center',
                background: '#fff',
                borderRadius: 16,
                boxShadow: '0 2px 8px #b0c4de',
                marginBottom: 18,
                padding: '18px 24px',
                cursor: 'pointer',
                transition: 'transform 0.1s',
                borderLeft: `10px solid ${LABELS[String(post.is_recruiting)]?.color}`,
                gap: 18,
              }}
            >
              <div style={{ display: 'flex', alignItems: 'center', minWidth: 0, gap: 8 }}>
                <span style={{
                  display: 'inline-block',
                  minWidth: 70,
                  textAlign: 'center',
                  padding: '4px 0',
                  borderRadius: 12,
                  background: LABELS[String(post.is_recruiting)]?.color,
                  color: '#fff',
                  fontWeight: 700,
                  fontSize: 15,
                  marginRight: 6,
                  flexShrink: 0,
                }}>{LABELS[String(post.is_recruiting)]?.text}</span>
                <span style={{
                  display: 'inline-block',
                  minWidth: 70,
                  textAlign: 'center',
                  padding: '4px 0',
                  borderRadius: 12,
                  background: memberTagColor,
                  color: '#fff',
                  fontWeight: 700,
                  fontSize: 15,
                  marginRight: 10,
                  flexShrink: 0,
                }}>남음 {post.member_count}명</span>
                <span style={{
                  fontWeight: 700,
                  fontSize: 18,
                  color: '#222',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                  minWidth: 0,
                }}>{post.title}</span>
              </div>
              <span style={{ flex: 2, display: 'flex', gap: 4 }}>
                {[post.region, post.age_group, post.skill_level]
                  .filter(Boolean)
                  .map((tag, i) => (
                    <span key={i} style={{
                      display: 'inline-block',
                      background: '#1976d2',
                      color: '#fff',
                      borderRadius: 8,
                      padding: '2px 8px',
                      fontSize: 13,
                    }}>{tag}</span>
                  ))}
              </span>
              <span style={{ flex: 1, color: '#388e3c', fontWeight: 600, fontSize: 15 }}>{post.author}</span>
              <span style={{ flex: 1, color: '#888', fontSize: 14 }}>{new Date(post.created_at).toLocaleDateString()}</span>
              <span style={{ flex: 0.7, color: '#607d8b', fontWeight: 700, fontSize: 15, textAlign: 'right' }}>{post.views}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

export default PostsList;
